// Parse the HTML response and check for promo indicators
const html = $input.first().json.data || '';

// Detect if promos are currently active
const promoIndicators = [
  'promo award',
  'promotion',
  'discounted',
  'flash sale',
  'limited time'
];

const lowerHtml = html.toLowerCase();
const hasPromos = promoIndicators.some(indicator => lowerHtml.includes(indicator));

// Extract any route mentions (rough heuristic)
const routePattern = /([A-Z]{3})\s*[→\-–]\s*([A-Z]{3})/g;
const routes = [];
let match;
while ((match = routePattern.exec(html)) !== null && routes.length < 10) {
  routes.push(`${match[1]} → ${match[2]}`);
}

// Check if we already sent an alert this month
const thisMonth = new Date().toISOString().slice(0, 7); // YYYY-MM

return [{
  json: {
    hasPromos,
    routes: [...new Set(routes)], // deduplicate
    month: thisMonth,
    checkedAt: new Date().toISOString(),
    url: 'https://www.flyingblue.com/en/earn/promo-awards'
  }
}];

// Log the check for debugging
console.log('Flying Blue check — no promos found or already sent', {
  month: $input.first().json.month,
  checkedAt: $input.first().json.checkedAt
});
return $input.all();
